using System;
using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using System.Data.Entity;
using System.Security.Cryptography;
using System.Text;

namespace ReviewApp.Controllers
{
    public class ProductController : Controller
    {
        private readonly MyDbContext _context = new MyDbContext();

        // GET: /Product/
        public ActionResult Index(int id)
        {
            var product = _context.Products.Find(id);
            if (product == null)
                return HttpNotFound();

            var reviews = _context.Reviews.Where(r => r.ProductId == id).ToList();
            return View(reviews);
        }

        [HttpPost]
        public ActionResult SubmitReview(int productId, string reviewText)
        {
            var hashedIp = GetHashedIp(Request.UserHostAddress);

            var review = new Review
            {
                ProductId = productId,
                Text = reviewText,
                IpAddress = hashedIp
            };

            _context.Reviews.Add(review);
            _context.SaveChanges();

            return RedirectToAction("Index", new { id = productId });
        }

        private string GetHashedIp(string ipAddress)
        {
            using (var sha256 = SHA256.Create())
            {
                var bytes = sha256.ComputeHash(Encoding.UTF8.GetBytes(ipAddress));
                return BitConverter.ToString(bytes).Replace("-", "").ToLower();
            }
        }
    }

    public class Review
    {
        public int Id { get; set; }
        public int ProductId { get; set; }
        public string Text { get; set; }
        public string IpAddress { get; set; }
    }

    public class MyDbContext : DbContext
    {
        public DbSet<Product> Products { get; set; }
        public DbSet<Review> Reviews { get; set; }
    }
}